+/**
+ * API Contract Validator
+ *
+ * Validates MCP tool interfaces to detect breaking changes.
+ *
+ * @module v3/testing/regression/api-contract
+ */
+
+import { readFile, writeFile, mkdir } from 'fs/promises';
+import { join, dirname } from 'path';
+
+/**
+ * Contract definition for a tool or endpoint
+ */
+export interface ContractDefinition {
+  name: string;
+  version: string;
+  description: string;
+  input: ParameterSchema;
+  output: ParameterSchema;
+  required: string[];
+  optional: string[];
+  errors: ErrorDefinition[];
+}
+
+/**
+ * Parameter schema definition
+ */
+interface ParameterSchema {
+  type: string;
+  properties?: Record<string, PropertyDefinition>;
+  items?: PropertyDefinition;
+  required?: string[];
+}
+
+/**
+ * Property definition
+ */
+interface PropertyDefinition {
+  type: string;
+  description?: string;
+  enum?: string[];
+  default?: unknown;
+  properties?: Record<string, PropertyDefinition>;
+  items?: PropertyDefinition;
+}
+
+/**
+ * Error definition
+ */
+interface ErrorDefinition {
+  code: number;
+  message: string;
+  description: string;
+}
+
+/**
+ * Contract validation result
+ */
+export interface ContractValidation {
+  endpoint: string;
+  valid: boolean;
+  breaking: boolean;
+  message: string;
+  diffs: ContractDiff[];
+}
+
+/**
+ * Contract difference
+ */
+export interface ContractDiff {
+  type: 'added' | 'removed' | 'changed' | 'deprecated';
+  path: string;
+  description: string;
+  breaking: boolean;
+  oldValue?: unknown;
+  newValue?: unknown;
+}
+
+/**
+ * Stored contracts
+ */
+interface StoredContracts {
+  version: string;
+  capturedAt: number;
+  contracts: ContractDefinition[];
+}
+
+/**
+ * MCP tool definitions to validate
+ */
+const MCP_TOOLS: ContractDefinition[] = [
+  {
+    name: 'agent/spawn',
+    version: '1.0.0',
+    description: 'Spawn a new agent',
+    input: {
+      type: 'object',
+      properties: {
+        agentType: { type: 'string', description: 'Type of agent to spawn' },
+        id: { type: 'string', description: 'Optional agent ID' },
+        config: { type: 'object', description: 'Agent configuration' },
+        priority: { type: 'string', enum: ['low', 'normal', 'high', 'critical'] },
+        metadata: { type: 'object', description: 'Additional metadata' },
+      },
+      required: ['agentType'],
+    },
+    output: {
+      type: 'object',
+      properties: {
+        agentId: { type: 'string' },
+        status: { type: 'string' },
+        createdAt: { type: 'string' },
+      },
+    },
+    required: ['agentType'],
+    optional: ['id', 'config', 'priority', 'metadata'],
+    errors: [
