+      { code: -32000, message: 'Agent spawn failed', description: 'Failed to spawn agent' },
+    ],
+  },
+  {
+    name: 'agent/list',
+    version: '1.0.0',
+    description: 'List all agents',
+    input: {
+      type: 'object',
+      properties: {
